import { createClient } from "@/lib/supabase/server";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import Link from "next/link";
import { Button } from "@/components/ui/button";

export default async function PatientsListPage() {
  const supabase = await createClient();

  const { data: patients, error } = await supabase
    .from("patients")
    .select("*")
    .order("created_at", { ascending: false })
    .limit(50);

  return (
    <div className="w-full">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">
            Liste des Patients
          </h1>
          <p className="text-muted-foreground mt-2">
            Consultez les dossiers patients récents.
          </p>
        </div>
        <div className="space-x-4">
          <Link href="/admin/import">
            <Button variant="outline">Importer CSV</Button>
          </Link>
          <Button>Nouveau Patient</Button>
        </div>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Patients</CardTitle>
          <CardDescription>
            {error
              ? "Erreur lors du chargement des patients."
              : `50 derniers patients enregistrés.`}
          </CardDescription>
        </CardHeader>
        <CardContent>
          {patients && patients.length > 0 ? (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>N° Patient</TableHead>
                  <TableHead>Nom</TableHead>
                  <TableHead>Prénom</TableHead>
                  <TableHead>Téléphone</TableHead>
                  <TableHead>Email</TableHead>
                  <TableHead className="text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {patients.map((patient) => (
                  <TableRow key={patient.id}>
                    <TableCell className="font-medium">
                      {patient.patient_number}
                    </TableCell>
                    <TableCell>{patient.last_name}</TableCell>
                    <TableCell>{patient.first_name}</TableCell>
                    <TableCell>{patient.phone_number || "-"}</TableCell>
                    <TableCell>{patient.email || "-"}</TableCell>
                    <TableCell className="text-right">
                      <Link href={`/admin/patients/${patient.id}`}>
                        <Button variant="ghost" size="sm">
                          Ouvrir le dossier
                        </Button>
                      </Link>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          ) : (
            <div className="py-10 text-center text-muted-foreground">
              Aucun patient trouvé. Importez-en un pour commencer.
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
